SELECT score, CUME_DIST() OVER (ORDER BY score) AS cumulative_distribution 
FROM exam_scores 
WHERE exam_id = 1;

SELECT scholarship_id, scholarship_name, SUM(amount) AS total_scholarship_amount
FROM scholarships
GROUP BY scholarship_id, scholarship_name;

SELECT student_id, SUM(amount) AS total_fees_paid
FROM fee_payments
GROUP BY student_id;

SELECT students.student_name, students.email
FROM students
INNER JOIN student_scholarships ON students.student_id = student_scholarships.student_id;
